const svg = $('#events-svg'), out = $('#events-out');
const W=760, H=260, pad=40;
const cell = 28;
const ox = (W - 6*cell)/2;
const oy = 40;
function drawGrid(highlight){
  svg.innerHTML = '';
  const hl = new Set((highlight||[]).map(([a,b])=>a+','+b));
  // axis labels
  for(let i=1;i<=6;i++){
    const tx = SVG('text',{x:ox+(i-0.5)*cell,y:oy-10,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    tx.textContent=i; svg.appendChild(tx);
    const ty = SVG('text',{x:ox-10,y:oy+(i-0.5)*cell+4,'text-anchor':'end','font-size':11,fill:'var(--mute)'});
    ty.textContent=i; svg.appendChild(ty);
  }
  // cells
  for(let a=1;a<=6;a++){
    for(let b=1;b<=6;b++){
      const x = ox+(a-1)*cell, y = oy+(b-1)*cell;
      const on = hl.has(a+','+b);
      svg.appendChild(SVG('rect',{x,y,width:cell-1,height:cell-1,
        fill: on ? 'var(--yellow)' : 'var(--panel2)',
        stroke:'var(--line)'}));
      const t = SVG('text',{x:x+cell/2,y:y+cell/2+4,'text-anchor':'middle','font-size':10,
        fill: on ? '#111' : 'var(--mute)'});
      t.textContent=a+b;
      svg.appendChild(t);
    }
  }
  // axis titles
  const xt = SVG('text',{x:ox+3*cell,y:oy+6*cell+24,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
  xt.textContent='die 1'; svg.appendChild(xt);
  const yt = SVG('text',{x:ox-30,y:oy+3*cell,'text-anchor':'middle','font-size':12,fill:'var(--mute)','transform':`rotate(-90 ${ox-30} ${oy+3*cell})`});
  yt.textContent='die 2'; svg.appendChild(yt);
}
function outcomes(pred){
  const res=[];
  for(let a=1;a<=6;a++) for(let b=1;b<=6;b++) if(pred(a,b)) res.push([a,b]);
  return res;
}
function show(label, pred){
  const es = outcomes(pred);
  drawGrid(es);
  out.textContent = `${label}\n|A| = ${es.length}, |Ω| = 36, P(A) = ${es.length}/36 ≈ ${(es.length/36).toFixed(4)}`;
}
$('#ev-sum10').addEventListener('click',()=>show('sum ≥ 10', (a,b)=>a+b>=10));
$('#ev-double').addEventListener('click',()=>show('doubles (a=b)', (a,b)=>a===b));
$('#ev-even').addEventListener('click',()=>show('sum even', (a,b)=>(a+b)%2===0));
$('#ev-both').addEventListener('click',()=>show('(sum ≥ 10) ∩ (doubles)', (a,b)=>a+b>=10 && a===b));
$('#ev-either').addEventListener('click',()=>show('(sum ≥ 10) ∪ (doubles)', (a,b)=>a+b>=10 || a===b));
$('#ev-reset').addEventListener('click',()=>{ drawGrid([]); out.textContent='Pick an event.'; });
drawGrid([]);

