const svg = $('#bayes-svg'), out = $('#b-out');
const prior=$('#b-prior'), sens=$('#b-sens'), fpr=$('#b-fpr');
const pv=$('#b-prior-v'), sv=$('#b-sens-v'), fv=$('#b-fpr-v');
const W=760, H=260;
function draw(){
  const p = +prior.value, s = +sens.value, f = +fpr.value;
  pv.textContent = p.toFixed(3);
  sv.textContent = s.toFixed(3);
  fv.textContent = f.toFixed(3);
  // posterior
  const num = s*p;
  const den = s*p + f*(1-p);
  const post = den>0 ? num/den : 0;
  svg.innerHTML = '';
  // 3 bars: prior, likelihood ratio, posterior
  const barW = 180, barH = 160;
  const y0 = 50, y1 = y0+barH;
  const labels = ['prior P(D)', 'P(+) = sens·p + fpr·(1-p)', 'posterior P(D|+)'];
  const vals = [p, den, post];
  const colors = ['var(--violet)','var(--cyan)','var(--yellow)'];
  for(let i=0;i<3;i++){
    const cx = 80 + i*240;
    // frame
    svg.appendChild(SVG('rect',{x:cx,y:y0,width:barW,height:barH,
      fill:'none',stroke:'var(--line)','stroke-width':1}));
    // filled bar
    const fh = Math.min(1,vals[i])*barH;
    svg.appendChild(SVG('rect',{x:cx,y:y1-fh,width:barW,height:fh,
      fill:colors[i],opacity:0.85}));
    // value
    const t=SVG('text',{x:cx+barW/2,y:y0-8,'text-anchor':'middle','font-size':13,fill:colors[i],'font-weight':600});
    t.textContent=vals[i].toFixed(4);
    svg.appendChild(t);
    // label
    const lbl=SVG('text',{x:cx+barW/2,y:y1+24,'text-anchor':'middle','font-size':11,fill:'var(--mute)'});
    lbl.textContent=labels[i];
    svg.appendChild(lbl);
  }
  // arrow from prior to posterior
  drawArrow(svg,[80+180,y0+barH/2],[80+480,y0+barH/2],{color:'var(--mute)',label:'Bayes',curve:-30,labelSide:0});
  out.textContent =
    `P(D) = ${p.toFixed(4)} · P(+|D) = ${s.toFixed(4)} · P(+|¬D) = ${f.toFixed(4)}\n`+
    `P(+)  = ${s.toFixed(3)}·${p.toFixed(3)} + ${f.toFixed(3)}·${(1-p).toFixed(3)} = ${den.toFixed(5)}\n`+
    `P(D|+) = (P(+|D)·P(D)) / P(+) = ${num.toFixed(5)} / ${den.toFixed(5)} ≈ ${post.toFixed(4)}\n`+
    `posterior / prior ratio = ${(post/p).toFixed(2)}×`;
}
prior.addEventListener('input',draw);
sens.addEventListener('input',draw);
fpr.addEventListener('input',draw);
draw();

