const svg = $('#rv-svg'), out = $('#rv-out');
const pick = $('#rv-pick');
const W=760, H=260;
let samples = [];
function resample(){ samples = Array.from({length:40},()=>Math.random()); draw(); }
function apply(u){
  const m = pick.value;
  if(m==='unif') return 2*u;
  if(m==='sq') return u*u;
  if(m==='exp') return -Math.log(Math.max(u,1e-9));
  return u;
}
function draw(){
  svg.innerHTML = '';
  // top row: Omega = [0,1]
  const y0 = 50, y1 = 170;
  const x0 = 80, x1 = W-80;
  svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x1,y2:y0,stroke:'var(--mute)','stroke-width':1.2}));
  svg.appendChild(SVG('line',{x1:x0,y1:y1,x2:x1,y2:y1,stroke:'var(--mute)','stroke-width':1.2}));
  // labels
  const lt1=SVG('text',{x:x0-12,y:y0+4,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  lt1.textContent='Ω = [0,1]'; svg.appendChild(lt1);
  // R range varies
  const xs = samples.map(apply);
  const xmax = Math.max(...xs.concat([1]));
  const lt2=SVG('text',{x:x0-12,y:y1+4,'text-anchor':'end','font-size':12,fill:'var(--mute)'});
  lt2.textContent=`ℝ [0,${xmax.toFixed(2)}]`; svg.appendChild(lt2);
  // tick labels
  for(const v of [0,0.5,1]){
    const xp = x0 + v*(x1-x0);
    svg.appendChild(SVG('line',{x1:xp,y1:y0-4,x2:xp,y2:y0+4,stroke:'var(--mute)'}));
    const t=SVG('text',{x:xp,y:y0-8,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent=v; svg.appendChild(t);
  }
  for(const v of [0, xmax/2, xmax]){
    const xp = x0 + (v/xmax)*(x1-x0);
    svg.appendChild(SVG('line',{x1:xp,y1:y1-4,x2:xp,y2:y1+4,stroke:'var(--mute)'}));
    const t=SVG('text',{x:xp,y:y1+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent=v.toFixed(2); svg.appendChild(t);
  }
  // draw samples: dot on top, dot on bottom, segment between
  samples.forEach((u,i)=>{
    const xu = x0 + u*(x1-x0);
    const v = apply(u);
    const xv = x0 + (v/xmax)*(x1-x0);
    svg.appendChild(SVG('line',{x1:xu,y1:y0,x2:xv,y2:y1,
      stroke:'var(--violet)','stroke-width':0.8,opacity:0.55}));
    svg.appendChild(SVG('circle',{cx:xu,cy:y0,r:3,fill:'var(--cyan)'}));
    svg.appendChild(SVG('circle',{cx:xv,cy:y1,r:3,fill:'var(--yellow)'}));
  });
  // title
  const t1 = SVG('text',{x:W/2,y:25,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
  t1.textContent = `X pushes ω from Ω to X(ω) in ℝ — the law is the resulting measure on ℝ.`;
  svg.appendChild(t1);
  out.textContent =
    `n = ${samples.length} samples\n` +
    `sample mean of X ≈ ${(xs.reduce((a,b)=>a+b,0)/xs.length).toFixed(4)}\n` +
    `min(X) = ${Math.min(...xs).toFixed(4)}, max(X) = ${Math.max(...xs).toFixed(4)}`;
}
$('#rv-resample').addEventListener('click',resample);
pick.addEventListener('change',draw);
resample();

