const svg = $('#dist-svg'), out = $('#d-out');
const pick = $('#d-pick'), params = $('#d-params');
const W=760, H=280;
const x0=60, x1=W-40, y0=30, y1=H-40;
function factorial(n){ let r=1; for(let k=2;k<=n;k++) r*=k; return r; }
function binomPMF(n,p,k){
  if(k<0||k>n) return 0;
  // compute C(n,k)
  let c=1; for(let i=0;i<k;i++) c = c*(n-i)/(i+1);
  return c*Math.pow(p,k)*Math.pow(1-p,n-k);
}
function poissonPMF(lam,k){ return Math.exp(-lam)*Math.pow(lam,k)/factorial(k); }
function setParams(conf){
  params.innerHTML = '';
  conf.forEach(c=>{
    const lbl = document.createElement('label');
    lbl.setAttribute('for','dp-'+c.name);
    lbl.textContent = c.label + ' ';
    params.appendChild(lbl);
    const inp = document.createElement('input');
    inp.type='range'; inp.id='dp-'+c.name; inp.min=c.min; inp.max=c.max; inp.step=c.step; inp.value=c.value;
    params.appendChild(inp);
    const sp = document.createElement('span');
    sp.className='small'; sp.id='dp-'+c.name+'-v';
    params.appendChild(sp);
    inp.addEventListener('input',draw);
  });
}
function val(name){ return +document.getElementById('dp-'+name).value; }
function axes(xmin,xmax,ymax,discrete){
  svg.innerHTML = '';
  svg.appendChild(SVG('line',{x1:x0,y1:y1,x2:x1,y2:y1,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x0,y2:y1,stroke:'var(--line)'}));
  // ticks
  const xticks = discrete ? [] : [xmin, (xmin+xmax)/2, xmax];
  for(const v of (discrete ? [xmin, Math.round((xmin+xmax)/2), xmax] : xticks)){
    const xp = x0 + (v-xmin)/(xmax-xmin)*(x1-x0);
    svg.appendChild(SVG('line',{x1:xp,y1:y1,x2:xp,y2:y1+4,stroke:'var(--mute)'}));
    const t=SVG('text',{x:xp,y:y1+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent=(typeof v==='number' && Math.abs(v-Math.round(v))<1e-9) ? v : v.toFixed(2);
    svg.appendChild(t);
  }
  const yticks = [0, ymax/2, ymax];
  for(const v of yticks){
    const yp = y1 - (v/ymax)*(y1-y0);
    svg.appendChild(SVG('line',{x1:x0-4,y1:yp,x2:x0,y2:yp,stroke:'var(--mute)'}));
    const t=SVG('text',{x:x0-8,y:yp+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
    t.textContent=v.toFixed(2); svg.appendChild(t);
  }
}
function plotDiscrete(support, pmf){
  let ymax = Math.max(...support.map(pmf));
  if(ymax<=0) ymax = 1;
  const xmin = support[0], xmax = support[support.length-1] + 1;
  axes(xmin, xmax, ymax*1.1, true);
  // PMF bars
  for(const k of support){
    const xp = x0 + (k+0.5-xmin)/(xmax-xmin)*(x1-x0);
    const h = (pmf(k)/ymax)*(y1-y0) / 1.1;
    svg.appendChild(SVG('rect',{x:xp-8, y:y1-h, width:16, height:h,
      fill:'var(--cyan)', opacity:0.85}));
  }
  // CDF (step) overlaid, normalized to ymax*1.1
  let cum = 0;
  let prev = y1;
  for(const k of support){
    cum += pmf(k);
    const xA = x0 + (k+0.5-xmin)/(xmax-xmin)*(x1-x0);
    const yA = y1 - cum*(y1-y0)/1.1; // CDF on [0,1], rescaled like the bars
    svg.appendChild(SVG('line',{x1:xA-12, y1:prev, x2:xA-12, y2:yA,
      stroke:'var(--yellow)','stroke-width':1.2}));
    svg.appendChild(SVG('line',{x1:xA-12, y1:yA, x2:xA+12, y2:yA,
      stroke:'var(--yellow)','stroke-width':1.2}));
    prev = yA;
  }
  const lbl = SVG('text',{x:x1-30,y:y0+12,'font-size':11,fill:'var(--yellow)'});
  lbl.textContent='CDF'; svg.appendChild(lbl);
