function plotContinuous(xmin,xmax, pdf, N=200){
  // ymax
  let ymax = 0;
  const xs = [];
  for(let i=0;i<=N;i++){
    const x = xmin + i*(xmax-xmin)/N;
    xs.push([x,pdf(x)]);
    if(pdf(x)>ymax) ymax = pdf(x);
  }
  if(ymax<=0) ymax=1;
  axes(xmin,xmax,ymax*1.1,false);
  // PDF curve
  let d = '';
  xs.forEach(([x,y],i)=>{
    const xp = x0 + (x-xmin)/(xmax-xmin)*(x1-x0);
    const yp = y1 - (y/(ymax*1.1))*(y1-y0);
    d += (i===0?'M':'L') + xp + ',' + yp + ' ';
  });
  svg.appendChild(SVG('path',{d, fill:'none', stroke:'var(--cyan)','stroke-width':2}));
  // CDF via cumulative trapezoid
  let c = 0;
  let d2 = '';
  xs.forEach(([x,y],i)=>{
    if(i>0) c += (xs[i][1]+xs[i-1][1])/2 * (xs[i][0]-xs[i-1][0]);
  });
  const total = c;
  c = 0;
  xs.forEach(([x,y],i)=>{
    if(i>0) c += (xs[i][1]+xs[i-1][1])/2 * (xs[i][0]-xs[i-1][0]);
    const xp = x0 + (x-xmin)/(xmax-xmin)*(x1-x0);
    const yp = y1 - (c/Math.max(total,1e-9))*(y1-y0)/1.1;
    d2 += (i===0?'M':'L') + xp + ',' + yp + ' ';
  });
  svg.appendChild(SVG('path',{d:d2, fill:'none', stroke:'var(--yellow)','stroke-width':1.4, 'stroke-dasharray':'4 3'}));
  const lbl = SVG('text',{x:x1-30,y:y0+12,'font-size':11,fill:'var(--yellow)'});
  lbl.textContent='CDF'; svg.appendChild(lbl);
  const lbl2 = SVG('text',{x:x1-30,y:y0+28,'font-size':11,fill:'var(--cyan)'});
  lbl2.textContent='PDF'; svg.appendChild(lbl2);
}
