const svg = $('#scale-svg'), out = $('#scale-out');
const W=760, H=260;
const cy = 160, padx = 70;
// point masses [x in [-5,5], weight >=0]
let masses = [
  {x:-3, w:1},
  {x: 0, w:1},
  {x: 2, w:1.5},
];
const xmin = -5, xmax = 5;
function X(v){ return padx + (v-xmin)/(xmax-xmin)*(W-2*padx); }
function norm(){ const s = masses.reduce((a,m)=>a+m.w,0); return s>0?s:1; }
function ex(){ return masses.reduce((a,m)=>a+m.x*m.w,0)/norm(); }
function vr(){
  const mu = ex();
  return masses.reduce((a,m)=>a+m.w*(m.x-mu)**2,0)/norm();
}
let dragIdx = -1;
function draw(){
  svg.innerHTML = '';
  const mu = ex(), sigma = Math.sqrt(vr());
  // pivot
  const pivotX = X(mu);
  // beam tilted slightly to show balance visually
  // beam always drawn horizontal for clarity; we show a "fulcrum" at mu.
  svg.appendChild(SVG('line',{x1:X(xmin),y1:cy,x2:X(xmax),y2:cy,
    stroke:'var(--line)','stroke-width':2}));
  // axis ticks
  for(let v=xmin; v<=xmax; v++){
    const xp = X(v);
    svg.appendChild(SVG('line',{x1:xp,y1:cy-4,x2:xp,y2:cy+4,stroke:'var(--mute)'}));
    if(v%1===0){
      const t = SVG('text',{x:xp,y:cy+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
      t.textContent=v; svg.appendChild(t);
    }
  }
  // fulcrum triangle under mu
  const fTri = SVG('polygon',{points:`${pivotX-10},${cy+26} ${pivotX+10},${cy+26} ${pivotX},${cy+6}`,
    fill:'var(--yellow)','stroke':'var(--yellow)'});
  svg.appendChild(fTri);
  const muT = SVG('text',{x:pivotX,y:cy+48,'text-anchor':'middle','font-size':11,fill:'var(--yellow)'});
  muT.textContent = 'E[X] = '+mu.toFixed(3);
  svg.appendChild(muT);
  // sigma bracket
  const sx1 = X(mu-sigma), sx2 = X(mu+sigma);
  svg.appendChild(SVG('line',{x1:sx1,y1:cy-70,x2:sx2,y2:cy-70,stroke:'var(--violet)','stroke-width':1.2}));
  svg.appendChild(SVG('line',{x1:sx1,y1:cy-66,x2:sx1,y2:cy-74,stroke:'var(--violet)','stroke-width':1.2}));
  svg.appendChild(SVG('line',{x1:sx2,y1:cy-66,x2:sx2,y2:cy-74,stroke:'var(--violet)','stroke-width':1.2}));
  const stxt = SVG('text',{x:(sx1+sx2)/2,y:cy-78,'text-anchor':'middle','font-size':10,fill:'var(--violet)'});
  stxt.textContent='±σ = '+sigma.toFixed(3);
  svg.appendChild(stxt);
  // mass circles
  masses.forEach((m,i)=>{
    const r = 8 + 6*Math.min(m.w,3);
    const xp = X(m.x);
    svg.appendChild(SVG('circle',{cx:xp,cy:cy-r, r, fill:'var(--cyan)',stroke:'var(--cyan)',
      'data-idx':i, class:'mass'}));
    const lbl = SVG('text',{x:xp,y:cy-r-r-4,'text-anchor':'middle','font-size':10,fill:'var(--cyan)'});
    lbl.textContent = `w=${m.w.toFixed(1)} @ ${m.x.toFixed(2)}`;
    svg.appendChild(lbl);
  });
  // instructions
  const inst = SVG('text',{x:W/2,y:25,'text-anchor':'middle','font-size':12,fill:'var(--mute)'});
  inst.textContent = 'click a mass and drag left/right — fulcrum rebalances at E[X]';
  svg.appendChild(inst);
  out.textContent =
    `masses: ${masses.map(m=>`${m.w.toFixed(2)}@${m.x.toFixed(2)}`).join(', ')}\n`+
    `total weight = ${norm().toFixed(3)}\n`+
    `E[X]  = ${mu.toFixed(4)}\n`+
    `Var(X) = ${vr().toFixed(4)}\n`+
    `σ = ${sigma.toFixed(4)}`;
}
svg.addEventListener('pointerdown',(ev)=>{
  const pt = svg.createSVGPoint();
  pt.x = ev.clientX; pt.y = ev.clientY;
  const loc = pt.matrixTransform(svg.getScreenCTM().inverse());
  // find nearest mass
  let best = -1, bd = 1e9;
  masses.forEach((m,i)=>{
    const d = Math.hypot(X(m.x)-loc.x, (cy-(8+6*Math.min(m.w,3)))-loc.y);
    if(d<bd){ bd = d; best = i; }
  });
  if(bd<30) dragIdx = best;
});
svg.addEventListener('pointermove',(ev)=>{
  if(dragIdx<0) return;
  const pt = svg.createSVGPoint();
  pt.x = ev.clientX; pt.y = ev.clientY;
  const loc = pt.matrixTransform(svg.getScreenCTM().inverse());
  // invert X
  const v = xmin + (loc.x-padx)/(W-2*padx)*(xmax-xmin);
  masses[dragIdx].x = Math.max(xmin, Math.min(xmax, v));
  draw();
});
svg.addEventListener('pointerup',()=>{ dragIdx = -1; });
svg.addEventListener('pointercancel',()=>{ dragIdx = -1; });
draw();

