const svg = $('#lln-svg'), out = $('#lln-out');
const pick = $('#lln-pick');
const W=760, H=280;
const x0=60, x1=W-40, y0=30, y1=H-40;
let samples = [];
let mu0 = 0.5;
function sampler(kind){
  if(kind==='bern') return ()=>Math.random()<0.5?1:0;
  if(kind==='unif') return ()=>Math.random();
  if(kind==='exp')  return ()=>-Math.log(Math.max(1e-9,Math.random()));
  if(kind==='cauchy') return ()=>Math.tan(Math.PI*(Math.random()-0.5));
  return ()=>Math.random();
}
function targetMu(kind){
  if(kind==='bern') return 0.5;
  if(kind==='unif') return 0.5;
  if(kind==='exp')  return 1;
  return NaN;
}
function reset(){ samples = []; mu0 = targetMu(pick.value); draw(); }
function run(){
  const f = sampler(pick.value);
  for(let i=0;i<500;i++) samples.push(f());
  draw();
}
function draw(){
  svg.innerHTML = '';
  // running mean
  const runs = [];
  let s=0;
  for(let i=0;i<samples.length;i++){
    s += samples[i];
    runs.push(s/(i+1));
  }
  const N = samples.length;
  if(N===0){
    const t = SVG('text',{x:W/2,y:H/2,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
    t.textContent = 'Hit "draw 500 more samples" to begin.';
    svg.appendChild(t);
    out.textContent = 'no samples yet';
    return;
  }
  // y range
  const ymin = Math.min(...runs, isFinite(mu0)?mu0:0) - 0.3;
  const ymax = Math.max(...runs, isFinite(mu0)?mu0:1) + 0.3;
  const X = i => x0 + (i/Math.max(N-1,1))*(x1-x0);
  const Y = v => y1 - (v-ymin)/(ymax-ymin)*(y1-y0);
  // axes
  svg.appendChild(SVG('line',{x1:x0,y1:y1,x2:x1,y2:y1,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x0,y2:y1,stroke:'var(--line)'}));
  // mu line
  if(isFinite(mu0)){
    svg.appendChild(SVG('line',{x1:x0,y1:Y(mu0),x2:x1,y2:Y(mu0),
      stroke:'var(--violet)','stroke-width':1.5,'stroke-dasharray':'4 4'}));
    const lbl=SVG('text',{x:x1-5,y:Y(mu0)-6,'text-anchor':'end','font-size':11,fill:'var(--violet)'});
    lbl.textContent = `μ = ${mu0}`;
    svg.appendChild(lbl);
  }
  // running mean polyline
  let d='';
  runs.forEach((v,i)=>{ d += (i===0?'M':'L')+X(i)+','+Math.max(y0,Math.min(y1,Y(v)))+' '; });
  svg.appendChild(SVG('path',{d,fill:'none',stroke:'var(--yellow)','stroke-width':1.8}));
  // ticks
  for(const v of [0, Math.round(N/2), N]){
    const xp = X(v-1<0?0:v-1);
    const t = SVG('text',{x:xp,y:y1+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent=v; svg.appendChild(t);
  }
  // title
  const tl = SVG('text',{x:W/2,y:18,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
  tl.textContent = 'running sample mean X̄_n vs n';
  svg.appendChild(tl);
  const tail = runs.slice(-1)[0];
  out.textContent =
    `samples so far: ${N}\n`+
    `running mean X̄_N = ${tail.toFixed(5)}\n`+
    (isFinite(mu0) ?
      `target μ = ${mu0} — gap |X̄_N − μ| = ${Math.abs(tail-mu0).toFixed(5)}\n`
    : `target μ undefined (Cauchy has no mean; sample mean does NOT concentrate)\n`) +
    `sample variance proxy: ${(runs.reduce((a,b)=>a+(b-tail)**2,0)/N).toExponential(2)}`;
}
$('#lln-run').addEventListener('click',run);
$('#lln-reset').addEventListener('click',reset);
pick.addEventListener('change',()=>{ reset(); });
reset();

