const svg = $('#clt-svg'), out = $('#clt-out');
const pick = $('#clt-pick'), sl = $('#clt-N'), slv = $('#clt-N-v');
const W=760, H=280;
const x0=60, x1=W-40, y0=30, y1=H-40;
function sampler(kind){
  if(kind==='bern') return ()=>Math.random()<0.3?1:0;
  if(kind==='unif') return ()=>Math.random();
  if(kind==='bim')  return ()=>Math.random()<0.5? 1+0.2*randn() : -1+0.2*randn();
  if(kind==='exp')  return ()=>-Math.log(Math.max(1e-9,Math.random()));
  return ()=>Math.random();
}
function stats(kind){
  if(kind==='bern') return {mu:0.3, sd:Math.sqrt(0.3*0.7)};
  if(kind==='unif') return {mu:0.5, sd:Math.sqrt(1/12)};
  if(kind==='bim')  return {mu:0,   sd:Math.sqrt(1+0.04)};
  if(kind==='exp')  return {mu:1,   sd:1};
  return {mu:0, sd:1};
}
function draw(){
  svg.innerHTML = '';
  const kind = pick.value, N = +sl.value;
  slv.textContent = 'N = '+N;
  const {mu,sd} = stats(kind);
  const f = sampler(kind);
  // 2000 trials
  const M = 2000;
  const zs = [];
  for(let t=0;t<M;t++){
    let s=0;
    for(let i=0;i<N;i++) s+=f();
    const m = s/N;
    const z = Math.sqrt(N)*(m - mu)/sd;
    zs.push(z);
  }
  // histogram
  const zmin=-4, zmax=4, bins=40;
  const binW=(zmax-zmin)/bins;
  const counts = new Array(bins).fill(0);
  for(const z of zs){
    if(z<zmin||z>=zmax) continue;
    counts[Math.floor((z-zmin)/binW)]++;
  }
  const density = counts.map(c=>c/(M*binW));
  const ymax = Math.max(...density, 0.5);
  // axes
  const X = z => x0 + (z-zmin)/(zmax-zmin)*(x1-x0);
  const Y = v => y1 - (v/(ymax*1.1))*(y1-y0);
  svg.appendChild(SVG('line',{x1:x0,y1:y1,x2:x1,y2:y1,stroke:'var(--line)'}));
  svg.appendChild(SVG('line',{x1:x0,y1:y0,x2:x0,y2:y1,stroke:'var(--line)'}));
  for(const zv of [-4,-2,0,2,4]){
    const xp = X(zv);
    const t=SVG('text',{x:xp,y:y1+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent=zv; svg.appendChild(t);
  }
  // histogram bars
  for(let k=0;k<bins;k++){
    const xa = X(zmin + k*binW);
    const xb = X(zmin + (k+1)*binW);
    const ya = Y(density[k]);
    svg.appendChild(SVG('rect',{x:xa, y:ya, width:xb-xa-1, height:y1-ya,
      fill:'var(--cyan)',opacity:0.55}));
  }
  // standard normal overlay
  let d='';
  for(let i=0;i<=200;i++){
    const z = zmin + i*(zmax-zmin)/200;
    const xp=X(z), yp=Y(phi(z));
