let counts = [0,0,0];
function P(){
  // build from 5 entries with row-sum constraint
  const p11 = Math.max(0,Math.min(1,+$('#mk-p11').value));
  const p12 = Math.max(0,Math.min(1,+$('#mk-p12').value));
  const p22 = Math.max(0,Math.min(1,+$('#mk-p22').value));
  const p23 = Math.max(0,Math.min(1,+$('#mk-p23').value));
  const p33 = Math.max(0,Math.min(1,+$('#mk-p33').value));
  const p13 = Math.max(0, 1 - p11 - p12);
  const p21 = Math.max(0, 1 - p22 - p23);
  const p31 = Math.max(0, (1 - p33)*0.5);
  const p32 = Math.max(0, 1 - p33 - p31);
  return [[p11,p12,p13],[p21,p22,p23],[p31,p32,p33]];
}
function stationary(M){
  // solve πM = π, πᵀ1=1. Power method on Mᵀ.
  let p = [1/3,1/3,1/3];
  for(let k=0;k<2000;k++){
    const np = [0,0,0];
    for(let j=0;j<3;j++) for(let i=0;i<3;i++) np[j] += p[i]*M[i][j];
    p = np;
  }
  const s = p.reduce((a,b)=>a+b,0);
  return p.map(v=>v/s);
}
function step(){
  const M = P();
  const r = Math.random();
  let c = 0;
  for(let j=0;j<3;j++){
    c += M[state][j];
    if(r<c){ state = j; break; }
  }
  counts[state]++;
  draw();
}
