        markerId:'mk-'+i+j
      });
    }
  }
  // self-loops indicated by readout only
  // nodes
  for(let i=0;i<3;i++){
    const cur = state===i;
    drawNode(svg, pts[i][0], pts[i][1], labels[i], {
      r: cur? 24 : 18, fill: cur?'var(--yellow)':'var(--panel2)',
      stroke: colors[i], textColor: cur? '#111':'#fff', fontSize: 14
    });
  }
