    svg.appendChild(SVG('rect',{x:x0,y:by,width:120*emp[i],height:bh,fill:colors[i],opacity:0.85}));
    // stationary marker
    svg.appendChild(SVG('line',{x1:x0+120*pi[i],y1:by-3,x2:x0+120*pi[i],y2:by+bh+3,
      stroke:'var(--ink)','stroke-width':1.8}));
    const t = SVG('text',{x:x0+60,y:by-4,'text-anchor':'middle','font-size':11,fill:colors[i]});
    t.textContent = `${labels[i]}: emp ${(emp[i]*100).toFixed(1)}% / π ${(pi[i]*100).toFixed(1)}%`;
    svg.appendChild(t);
  }
  const cap = SVG('text',{x:W/2,y:25,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
  cap.textContent = '3-state chain: edit P entries, step, watch empirical freq → π';
  svg.appendChild(cap);
  out.textContent =
    `steps taken: ${total}, current state: ${labels[state]}\n`+
    `stationary π ≈ [${pi.map(v=>v.toFixed(3)).join(', ')}]\n`+
    `empirical  ≈ [${emp.map(v=>v.toFixed(3)).join(', ')}]\n`+
    `row sums (should be 1): [${M.map(r=>r.reduce((a,b)=>a+b,0).toFixed(3)).join(', ')}]`;
}
