  }
  svg.appendChild(SVG('path',{d:de,fill:'none',stroke:'var(--violet)','stroke-width':1.2,'stroke-dasharray':'2 3'}));
  svg.appendChild(SVG('path',{d:du,fill:'none',stroke:'var(--violet)','stroke-width':1.2,'stroke-dasharray':'2 3'}));
  // ticks
  for(const tv of [0,0.5,1]){
    const xp=X(tv); const t=SVG('text',{x:xp,y:y1+18,'text-anchor':'middle','font-size':10,fill:'var(--mute)'});
    t.textContent=tv; svg.appendChild(t);
  }
  for(const vv of [-3,-2,-1,0,1,2,3]){
    const yp=Y(vv); const t=SVG('text',{x:x0-6,y:yp+4,'text-anchor':'end','font-size':10,fill:'var(--mute)'});
    t.textContent=vv; svg.appendChild(t);
  }
  // draw paths
  paths.forEach((p,k)=>{
    let d='';
    p.forEach((v,i)=>{
      const t = i/(p.length-1);
      d += (i===0?'M':'L')+X(t)+','+Y(v)+' ';
    });
    svg.appendChild(SVG('path',{d,fill:'none',
      stroke: paths.length>1?'var(--cyan)':'var(--yellow)',
      'stroke-width': paths.length>1?0.8:1.6,
      opacity: paths.length>1?0.55:1
    }));
  });
  // legend
  const lg = SVG('text',{x:x1-10,y:y0+14,'text-anchor':'end','font-size':11,fill:'var(--violet)'});
  lg.textContent='±2√t (≈ 95% band)';
  svg.appendChild(lg);
  // title
  const tl = SVG('text',{x:W/2,y:20,'text-anchor':'middle','font-size':13,fill:'var(--mute)'});
  tl.textContent = `Brownian motion on [0,1], N=${N} steps; step var ∝ 1/N confirms √N scaling`;
  svg.appendChild(tl);
  // out
  if(paths.length===1){
    const p = paths[0];
    const qv = p.slice(1).reduce((acc,v,i)=>acc+(v-p[i])**2,0);
    out.textContent =
      `single path with N=${N} steps\n`+
      `W_1 sample  = ${p[p.length-1].toFixed(4)}\n`+
      `quadratic variation Σ(ΔW)² = ${qv.toFixed(4)}  (converges to t=1 as N→∞)\n`+
      `total variation Σ|ΔW| = ${p.slice(1).reduce((a,v,i)=>a+Math.abs(v-p[i]),0).toFixed(2)} (→ ∞)`;
  } else if(paths.length>1){
    const w1s = paths.map(p=>p[p.length-1]);
    const m = w1s.reduce((a,b)=>a+b,0)/w1s.length;
    const s = w1s.reduce((a,b)=>a+(b-m)**2,0)/w1s.length;
    out.textContent =
      `${paths.length} overlaid paths, N=${N} steps each\n`+
      `empirical mean of W_1 ≈ ${m.toFixed(3)}  (target 0)\n`+
      `empirical var  of W_1 ≈ ${s.toFixed(3)}  (target 1)`;
  } else {
    out.textContent = 'Click "new path" to simulate.';
  }
}
$('#bm-new').addEventListener('click',newPath);
$('#bm-many').addEventListener('click',many);
$('#bm-reset').addEventListener('click',reset);
sl.addEventListener('input',()=>{ slv.textContent = 'N = '+sl.value; });
newPath();
